import { Outlet, Link, useLocation } from 'react-router-dom';
import s from './TestEngineShell.module.css';

const TABS = [
  { label: 'Backtest Runner', path: '/test-engine/backtest', icon: '\u25B6' },
  { label: 'Results',         path: '/test-engine/results',  icon: '\u25A3' },
  { label: 'Optimization',    path: '/test-engine/optimize', icon: '\u2699' },
  { label: 'Promotions',      path: '/test-engine/promotions', icon: '\u2B06' },
];

export default function TestEngineShell() {
  const location = useLocation();

  const isActive = (path) => {
    if (path === '/test-engine/backtest' && location.pathname === '/test-engine') return true;
    return location.pathname === path || location.pathname.startsWith(path + '/');
  };

  return (
    <div className={s.shell}>
      {/* Header bar */}
      <div className={s.header}>
        {/* Title row */}
        <div className={s.titleRow}>
          <div className={s.titleLeft}>
            <div className={s.logoBox} style={{
              background: 'linear-gradient(135deg, var(--color-purple, #A78BFA), var(--color-blue, #60A5FA))',
            }}>
              A
            </div>
            <div>
              <h1 className={s.titleText}>AURA Alpha Test Engine</h1>
              <p className={s.titleSub}>Backtest, optimize, and promote strategies</p>
            </div>
          </div>

          {/* Status badges */}
          <div className={s.badges}>
            <span className={s.badge} style={{
              background: 'color-mix(in srgb, var(--color-blue, #60A5FA) 8%, transparent)',
              color: 'var(--color-blue, #60A5FA)',
            }}>
              DESKTOP ONLY
            </span>
          </div>
        </div>

        {/* Tab bar */}
        <nav className={s.tabBar}>
          {TABS.map(tab => {
            const active = isActive(tab.path);
            return (
              <Link
                key={tab.path}
                to={tab.path}
                className={`${s.tab} ${active ? s.tabActive : ''}`}
              >
                <span className={s.tabIcon}>{tab.icon}</span>
                {tab.label}
              </Link>
            );
          })}
        </nav>
      </div>

      {/* Mobile warning overlay */}
      <div className={s.mobileWarning}>
        <div className={s.mobileInner}>
          <div className={s.mobileIcon}>&#9000;</div>
          <h2 className={s.mobileTitle}>Desktop Required</h2>
          <p className={s.mobileText}>
            The Test Engine is designed for desktop use. Please switch to a larger screen for the full experience.
          </p>
          <Link to="/" className={s.mobileLink}>
            Return to Command Center
          </Link>
        </div>
      </div>

      {/* Content area */}
      <div className={s.content}>
        <Outlet />
      </div>
    </div>
  );
}
